import Foundation
import WhisperKit

@available(macOS 14.0, *)
actor WhisperKitASRService {
    private let config: WhisperKitConfig
    private var whisperKit: WhisperKit?

    init(config: WhisperKitConfig? = nil) {
        self.config = config ?? WhisperKitConfig(
            model: "tiny",
            verbose: false,
            load: false,
            download: false
        )
    }

    func prepareIfNeeded() async throws {
        guard whisperKit == nil else { return }
        whisperKit = try await WhisperKit(config)
    }

    func transcribe(audioSamples: [Float]) async throws -> [ASRTranscriptEvent] {
        try await prepareIfNeeded()
        guard let whisperKit else { return [] }

        let options = DecodingOptions(wordTimestamps: true)
        let results = try await whisperKit.transcribe(audioArray: audioSamples, decodeOptions: options)

        return results.flatMap { result in
            result.segments.map { segment in
                ASRTranscriptEvent(
                    id: UUID(),
                    startTimeSeconds: Double(segment.start),
                    endTimeSeconds: Double(segment.end),
                    text: segment.text.trimmingCharacters(in: .whitespacesAndNewlines),
                    isFinal: true
                )
            }
        }
    }
}

import Foundation
import SpeakerKit

@available(macOS 14.0, *)
actor SpeakerKitDiarizationService {
    private let config: PyannoteConfig
    private var speakerKit: SpeakerKit?

    init(config: PyannoteConfig? = nil) {
        self.config = config ?? PyannoteConfig(
            download: false,
            load: false,
            verbose: false
        )
    }

    func prepareIfNeeded() async throws {
        guard speakerKit == nil else { return }
        speakerKit = try await SpeakerKit(config)
    }

    func diarize(audioSamples: [Float]) async throws -> [SpeakerSegmentEvent] {
        try await prepareIfNeeded()
        guard let speakerKit else { return [] }

        let result = try await speakerKit.diarize(audioArray: audioSamples)
        return result.segments.map { segment in
            let speakerLabel = segment.speaker.speakerId.map { "S\($0)" } ?? "UNKNOWN"
            return SpeakerSegmentEvent(
                id: segment.id,
                startTimeSeconds: Double(segment.startTime),
                endTimeSeconds: Double(segment.endTime),
                speakerLabel: speakerLabel,
                confidence: nil
            )
        }
    }
}

