18	    var body: some View {
19	        Group {
20	            if service.recordings.isEmpty {
21	                emptyState
22	            } else {
23	                recordingList
24	            }
25	        }
26	        .onAppear {
27	            service.loadRecordings()
28	        }
29	        .sheet(item: Binding(
30	            get: { selectedTranscriptionText.map { IdentifiableString(value: $0, subtitle: selectedTranscriptionDate ?? "") } },
31	            set: { _ in selectedTranscriptionText = nil; selectedTranscriptionDate = nil }
32	        )) { item in
33	            TranscriptionTextView(text: item.value, title: item.subtitle)
34	        }
35	    }
36	
37	    // MARK: 空状态
38	
39	    private var emptyState: some View {
40	        VStack(spacing: 8) {
41	            Image(systemName: "waveform.slash")
42	                .font(.largeTitle)
43	                .foregroundColor(.secondary)
44	            Text("暂无录音记录")
45	                .font(.callout)
46	                .foregroundColor(.secondary)
47	            Text("开始录音后，录音文件将自动保存在此处")
48	                .font(.caption)
49	                .foregroundColor(.secondary)
50	                .multilineTextAlignment(.center)
51	        }
52	        .frame(maxWidth: .infinity, maxHeight: .infinity)
53	        .padding()
54	    }
55	
56	    // MARK: 列表
57	
58	    private var recordingList: some View {
59	        List {
60	            ForEach(service.recordings) { item in
61	                RecordingRowView(
62	                    item: item,
63	                    isPlaying: currentlyPlayingId == item.id,
64	                    onPlayPause: { handlePlayPause(item: item) },
65	                    onRevealInFinder: { revealInFinder(item: item) },
66	                    onDelete: { service.delete(item: item) },
67	                    onViewTranscription: {
68	                        selectedTranscriptionText = item.preferredTranscriptionText
69	                        selectedTranscriptionDate = item.formattedDate
70	                    }
71	                )
72	                .listRowInsets(EdgeInsets(top: 4, leading: 8, bottom: 4, trailing: 8))
73	            }
74	        }
75	        .listStyle(.plain)
76	        .onChange(of: currentlyPlayingId) {
77	            if currentlyPlayingId == nil {
78	                player.stop()
79	            }
80	        }
81	    }
82	
83	    // MARK: 播放逻辑
84	
85	    private func handlePlayPause(item: RecordingItem) {
86	        if currentlyPlayingId == item.id {
87	            // 暂停
88	            player.pause()
89	            currentlyPlayingId = nil
90	        } else {
91	            // 停止前一条，播放新的
92	            player.stop()
93	            currentlyPlayingId = item.id
94	            player.play(url: item.url) {
95	                // 播放结束回调
96	                Task { @MainActor in
97	                    if currentlyPlayingId == item.id {
98	                        currentlyPlayingId = nil
99	                    }
100	                }
101	            }
102	        }
103	    }
104	
105	    // MARK: Finder 定位
106	
107	    private func revealInFinder(item: RecordingItem) {
108	        if FileManager.default.fileExists(atPath: item.url.path) {
109	            NSWorkspace.shared.activateFileViewerSelecting([item.url])
110	        } else {
111	            service.loadRecordings()
112	        }
113	    }
114	}
